using System;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    /// <summary>
    /// AOT-compatible JsonConverter for <see cref="ResponseError"/>.
    /// Required because the built-in converter for ResponseError uses an inaccessible nested type.
    /// </summary>
    internal sealed class AotResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            if (reader.TokenType == JsonTokenType.Null)
            {
                return null;
            }

            string code = null;
            string message = null;

            if (reader.TokenType != JsonTokenType.StartObject)
            {
                throw new JsonException("Expected StartObject token");
            }

            while (reader.Read())
            {
                if (reader.TokenType == JsonTokenType.EndObject)
                {
                    break;
                }

                if (reader.TokenType != JsonTokenType.PropertyName)
                {
                    continue;
                }

                string propertyName = reader.GetString();
                reader.Read();

                switch (propertyName)
                {
                    case "code":
                        code = reader.GetString();
                        break;
                    case "message":
                        message = reader.GetString();
                        break;
                    default:
                        reader.Skip();
                        break;
                }
            }

            return new ResponseError(code, message);
        }

        public override void Write(Utf8JsonWriter writer, ResponseError value, JsonSerializerOptions options)
        {
            if (value == null)
            {
                writer.WriteNullValue();
                return;
            }

            writer.WriteStartObject();
            if (value.Code != null)
            {
                writer.WriteString("code", value.Code);
            }
            if (value.Message != null)
            {
                writer.WriteString("message", value.Message);
            }
            writer.WriteEndObject();
        }
    }
}

